262	function resolveTelegramCommandConversation(params: {
263	  threadId?: string;
264	  originatingTo?: string;
265	  commandTo?: string;
266	  fallbackTo?: string;
267	}) {
268	  const chatId = [params.originatingTo, params.commandTo, params.fallbackTo]
269	    .map((candidate) => {
270	      const trimmed = candidate?.trim();
271	      return trimmed ? parseTelegramTarget(trimmed).chatId.trim() : "";
272	    })
273	    .find((candidate) => candidate.length > 0);
274	  if (!chatId) {
275	    return null;
276	  }
277	  if (params.threadId) {
278	    return {
279	      conversationId: `${chatId}:topic:${params.threadId}`,
280	      parentConversationId: chatId,
281	    };
282	  }
283	  if (chatId.startsWith("-")) {
284	    return null;
285	  }
286	  return {
287	    conversationId: chatId,
288	    parentConversationId: chatId,
289	  };
290	}
