```typescript
export type { PluginRuntime } from "../plugins/runtime/types.js";

export function createPluginRuntimeStore<T>(errorMessage: string) {
  let runtime: T | null = null;

  return {
    setRuntime(next: T) { runtime = next; },
    clearRuntime() { runtime = null; },
    tryGetRuntime() { return runtime; },
    getRuntime() {
      if (!runtime) throw new Error(errorMessage);
      return runtime;
    },
  };
}
```

**Pattern Usage in Telegram:**
- Single runtime slot per plugin
- Supports optional getter (`tryGetRuntime()`) for graceful degradation
- Error-throwing getter for mandatory scenarios
- Allows test/deployment-time injection of mock implementations

