// getChatChannelMeta(id) is a registry lookup for built-in channels only
// (src/channels/chat-meta.ts). Since "pulseboard" is a new extension plugin
// and not in the built-in CHAT_CHANNEL_ORDER list, calling it with "pulseboard"
// would throw at runtime. The ChannelMeta is therefore constructed directly
// below with the same shape getChatChannelMeta would return.
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";

/** Minimal resolved account shape used by the config and gateway adapters. */
type ResolvedPulseBoardAccount = {
  accountId: string;
  boardUrl: string;
  apiToken: string;
  username: string;
  enabled: boolean;
  configured: boolean;
};

const meta = {
  id: "pulseboard",
  label: "PulseBoard",
  selectionLabel: "PulseBoard (Bulletin)",
  docsPath: "/channels/pulseboard",
  blurb: "PulseBoard bulletin messaging — post to boards or send direct messages.",
};

export const pulseBoardPlugin: ChannelPlugin =
  createChatChannelPlugin<ResolvedPulseBoardAccount>({
    base: {
      id: "pulseboard",
      meta,
      capabilities: {
        chatTypes: ["direct", "group"],
        media: false,
      },
      reload: {
        configPrefixes: ["channels.pulseboard"],
      },
      config: {
        listAccountIds: (_cfg) => ["default"],
        resolveAccount: (_cfg, _accountId): ResolvedPulseBoardAccount => ({
          accountId: "default",
          boardUrl: "",
          apiToken: "",
          username: "",
          enabled: true,
          configured: false,
        }),
      },
      setup: {
        // Stub: return config unchanged until real onboarding is implemented.
        applyAccountConfig: ({ cfg }) => cfg,
      },
      gateway: {
        // Stub: no-op connection for fictional PulseBoard platform.
        startAccount: async (_ctx) => undefined,
      },
      messaging: {
        normalizeTarget: (raw) => raw.trim() || undefined,
      },
    },
    outbound: {
      base: {
        deliveryMode: "direct",
        textChunkLimit: 4000,
      },
      attachedResults: {
        channel: "pulseboard",
        // Stub: returns a synthetic message ID without a real network call.
        sendText: async (ctx) => ({
          messageId: `pb-${ctx.to}-${Date.now()}`,
        }),
      },
    },
  });

